import{_ as t,o as a,c as o,a3 as s}from"./chunks/framework.BveOjhN0.js";const g=JSON.parse('{"title":"Leads — User Guide","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Leads — User Guide | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/user-guide/leads"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Leads — User Guide | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/user-guide/leads"}]]},"headers":[],"relativePath":"user-guide/leads.md","filePath":"user-guide/leads.md","lastUpdated":1784377329000}'),r={name:"user-guide/leads.md"};function n(i,e,l,d,p,c){return a(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="leads-—-user-guide" tabindex="-1">Leads — User Guide <a class="header-anchor" href="#leads-—-user-guide" aria-label="Permalink to &quot;Leads — User Guide&quot;">​</a></h1><h2 id="who-can-use-leads" tabindex="-1">Who can use Leads <a class="header-anchor" href="#who-can-use-leads" aria-label="Permalink to &quot;Who can use Leads&quot;">​</a></h2><p>Your workspace must have the <strong>Leads</strong> module installed (included by default on new workspaces). Your role must include the relevant permissions (<code>view</code>, <code>create</code>, <code>update</code>, <code>delete</code>, <code>assign</code>, <code>export</code>, <code>import</code>, <code>convert</code> as needed).</p><p>Without <strong>assign</strong>, you only see leads assigned to you.</p><h2 id="board-table" tabindex="-1">Board &amp; table <a class="header-anchor" href="#board-table" aria-label="Permalink to &quot;Board &amp; table&quot;">​</a></h2><p>Open <strong>Leads</strong> from the sidebar. The default view is the <strong>Kanban board</strong> (columns = pipeline stages). Switch to <strong>Table</strong> when you prefer a list.</p><ul><li>Search by name, email, phone, or company</li><li>Filter by stage, status, priority, assignee, and lead value range</li><li>KPI cards summarize totals, pipeline value, follow-ups, and conversion metrics for your scope</li></ul><h2 id="create-edit" tabindex="-1">Create &amp; edit <a class="header-anchor" href="#create-edit" aria-label="Permalink to &quot;Create &amp; edit&quot;">​</a></h2><ol><li>Click <strong>New lead</strong></li><li>Enter name (required) and optional contact / company / source / <strong>lead value</strong> / priority / status</li><li>Optionally set stage and assignee (assignee requires <strong>assign</strong>)</li><li>Save</li></ol><p>Edit from the row menu or the detail drawer.</p><h2 id="pipeline-vs-status" tabindex="-1">Pipeline vs status <a class="header-anchor" href="#pipeline-vs-status" aria-label="Permalink to &quot;Pipeline vs status&quot;">​</a></h2><ul><li><strong>Stage</strong> — where the lead sits in the sales pipeline (New … Won / Lost). Moving a card on the board proposes a stage change; open the drawer and <strong>Save</strong> to commit (Cancel restores the card).</li><li><strong>Status</strong> — lifecycle state managed separately: Active, Waiting, On hold, Closed, Archived. Changing stage does <strong>not</strong> automatically change status.</li></ul><h2 id="assignment" tabindex="-1">Assignment <a class="header-anchor" href="#assignment" aria-label="Permalink to &quot;Assignment&quot;">​</a></h2><p>Users with <strong>assign</strong> can set or clear the assignee. Assignment changes are recorded in <strong>Assignment history</strong>. The assignee receives an in-app realtime notification when someone else assigns them. Lead-assignment email is disabled in v1.</p><h2 id="notes-follow-ups" tabindex="-1">Notes &amp; follow-ups <a class="header-anchor" href="#notes-follow-ups" aria-label="Permalink to &quot;Notes &amp; follow-ups&quot;">​</a></h2><ul><li><strong>Notes</strong> — free-form history on the lead</li><li><strong>Follow-ups</strong> — titled reminders with due dates; edit/reschedule or complete when done</li><li>Assignees receive notifications when a follow-up is created for them (by someone else) and when due/overdue reminders run</li></ul><h2 id="whatsapp-communication-templates" tabindex="-1">WhatsApp (Communication Templates) <a class="header-anchor" href="#whatsapp-communication-templates" aria-label="Permalink to &quot;WhatsApp (Communication Templates)&quot;">​</a></h2><p>When the <strong>Communication Templates</strong> module is installed and you have <strong>use</strong> permission:</p><ol><li>Open a lead that has a phone number</li><li>Click <strong>WhatsApp</strong> next to the phone</li><li>Choose a template, preview the filled message, then <strong>Open WhatsApp</strong></li></ol><p>WhatsApp opens with the message pre-filled. SaleOS does not send the message for you. See <a href="/user-guide/communication-templates">Communication Templates</a>.</p><h2 id="convert" tabindex="-1">Convert <a class="header-anchor" href="#convert" aria-label="Permalink to &quot;Convert&quot;">​</a></h2><p>Users with <strong>convert</strong> can mark a lead converted. Today this is a <strong>stub</strong>: the lead is stamped with <code>converted_at</code>, status becomes Closed, and an activity is recorded. Creating Contact/Company records is deferred until those modules ship.</p><h2 id="export" tabindex="-1">Export <a class="header-anchor" href="#export" aria-label="Permalink to &quot;Export&quot;">​</a></h2><p>Users with <strong>export</strong> can download the current filtered set as <strong>CSV</strong> or <strong>XLSX</strong>.</p><h2 id="import" tabindex="-1">Import <a class="header-anchor" href="#import" aria-label="Permalink to &quot;Import&quot;">​</a></h2><p>Users with <strong>import</strong> can bulk-load leads from <strong>CSV</strong> or <strong>XLSX</strong>:</p><ol><li>Open <strong>Import</strong> and download a sample template if needed</li><li>Upload a file (drag &amp; drop or browse)</li><li>Map spreadsheet columns to lead fields (Name is required)</li><li>Choose unique fields (<strong>Email</strong> / <strong>Phone</strong>) and duplicate behavior (<strong>Skip</strong>, <strong>Update existing</strong>, or <strong>Keep duplicate</strong>)</li><li>Preview counts and validation errors (nothing is written yet)</li><li>Start the import — it runs in the background; watch progress until complete</li></ol><p><strong>Update existing</strong> also requires the <strong>update</strong> permission.</p><p>Use <strong>Import history</strong> to review past imports, download the original file, <strong>failed_records.csv</strong>, or <strong>error_report.csv</strong>. Fix failed rows and upload again.</p><h2 id="activity-timeline" tabindex="-1">Activity timeline <a class="header-anchor" href="#activity-timeline" aria-label="Permalink to &quot;Activity timeline&quot;">​</a></h2><p>The <strong>Activity</strong> tab shows create, update, stage, assignment, note, follow-up, convert, and related events.</p>',31)])])}const m=t(r,[["render",n]]);export{g as __pageData,m as default};
